var e=[{id:`L3_1`,type:`dialog`,speaker:`PAWN_REPLACER_NULL_SPLIT`,text:{KOREA:`쿠에에엑!!`,JPN:`うがあああ！！`,ENG:`Groooar!!`,TWN:`呃啊啊啊！`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:null,C:{char_id:`PAWN_REPLACER_NULL_SPLIT`,face:`UNIT_SURPRISE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`PAWN_REPLACER_NULL_SPLIT`,text:{KOREA:`어째서...... 어째서 내가 이런 놈들에게!!`,JPN:`なぜだ……なぜ俺がこんな奴らに！！`,ENG:`Why? Why am I losing to these lowly worms?`,TWN:`怎麼可能……我怎麼會被這些傢伙給！！`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:null,C:{char_id:`PAWN_REPLACER_NULL_SPLIT`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`ORCA_RSEVEN_NULL_NULL`,text:{KOREA:`허억...... 허억......`,JPN:`はあ、はあ……`,ENG:`Huff, huff...`,TWN:`哈……哈……`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:null,C:{char_id:`ORCA_RSEVEN_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`해, 해치웠나?`,JPN:`こ、これで全滅か？`,ENG:`A-are they all dead?`,TWN:`解、解決掉了嗎？`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L10_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`저기! 더 몰려온다!!`,JPN:`向こうから！　また来る！！`,ENG:`There! More of them are coming!`,TWN:`那邊！又有更多湧過來了！！`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L11_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`분열체라더니...... 정말 끝이 없구만!`,JPN:`分裂体らしいよな……キリがねえ！`,ENG:`The name "splitters" really does them justice. They're coming at us in endless swarms.`,TWN:`分裂體果然……沒完沒了啊！`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L12_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:`그래도 이 정도면 꽤 상대할 만......`,JPN:`けど、これなら手に負えないことはな……`,ENG:`But they're just not that difficult to deal with—`,TWN:`但這種程度應該還是可以……`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`CHARLIE_RSEVEN_NULL_NULL`,text:{KOREA:` 응?`,JPN:`うん？`,ENG:` Hm?`,TWN:`嗯？`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L14_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`......저 녀석들 지금 뭘 하는 거야?`,JPN:`……あいつら、なにしてるの？`,ENG:`What are they doing now?`,TWN:`……那些傢伙在幹什麼？`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L15_1`,type:`dialog`,speaker:`JESSICA_RSEVEN_NULL_NULL`,text:{KOREA:`설마...... 합체라도 하는 건가?`,JPN:`まさか……合体でもするつもり？`,ENG:`No, it can't be... They're not combining into a single giant monster, are they?`,TWN:`該不會……是在合體？`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:{char_id:`JESSICA_RSEVEN_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHARLIE_RSEVEN_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L20_1`,type:`dialog`,speaker:`PAWN_REPLACER_NULL_FUSION`,text:{KOREA:`여긴 어디지......? 내가 왜......?`,JPN:`ここはどこだ……？　なぜ俺が……？`,ENG:`Where am I? How did I end up here?`,TWN:`這裡是哪裡……？為什麼……？`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:null,C:{char_id:`PAWN_REPLACER_NULL_FUSION`,face:`UNIT_SURPRISE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`PAWN_REPLACER_NULL_FUSION`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:null,C:{char_id:`PAWN_REPLACER_NULL_FUSION`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`PAWN_REPLACER_NULL_FUSION`,text:{KOREA:`아아 그렇군...... 이제야 기억이 나는 것 같아......`,JPN:`ああ、そうか……やっと思い出せそうだ……`,ENG:`Ah... Yes... I remember now.`,TWN:`啊啊，原來如此……我好像想起來了……`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:null,C:{char_id:`PAWN_REPLACER_NULL_FUSION`,face:`UNIT_LAUGH`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`PAWN_REPLACER_NULL_FUSION`,text:{KOREA:`큭...... 크큭...... 난 대체 뭘 한 거지......?`,JPN:`くっ……くっくっく……俺はいったい何をしてきたんだ。`,ENG:`Heh... Heh heh... What have I done?`,TWN:`呵……呵呵……我到底做了什麼……？`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:null,C:{char_id:`PAWN_REPLACER_NULL_FUSION`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`PAWN_REPLACER_NULL_FUSION`,text:{KOREA:`겨우 이런 꼴이 되려고...... 그 모든 굴욕을 감수한 건가......?`,JPN:`こんな姿になるために……あの屈辱に耐えてきたのか……？`,ENG:`Did I do all those things just to end up like this?`,TWN:`我就為了成為這個鬼樣子……忍受了所有的屈辱嗎……？`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:null,C:{char_id:`PAWN_REPLACER_NULL_FUSION`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`PAWN_REPLACER_NULL_FUSION`,text:{KOREA:`......뭐, 상관없겠지.`,JPN:`……まあ、いいだろう。`,ENG:`Well, it doesn't matter anymore.`,TWN:`……算了，無所謂了。`},stage:{bg:`COUNTERSIDE_GREEN`,slots:{L:null,C:{char_id:`PAWN_REPLACER_NULL_FUSION`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};